const stage = document.querySelector('#stage');
const counter = document.querySelector('#counter');
const prevButton = document.querySelector('#prev');
const nextButton = document.querySelector('#next');
const fullscreenButton = document.querySelector('#fullscreen');

let slides = [];
let current = 0;

const BACK_TARGETS = {
  1: 0,
  3: 2,
  4: 2,
  5: 2,
  6: 2,
  9: 0,
  12: 11,
  13: 11,
  14: 11,
  15: 11,
  16: 11,
  17: 11,
  18: 11,
  20: 19,
  21: 19,
  22: 19,
  23: 19,
  24: 19,
  25: 0,
  26: 0
};

const STACKED_BACK_BUTTON_SLIDES = new Set([14, 15, 18, 25]);

const MOBILE_VIDEO_QUERY = window.matchMedia('(max-width: 720px), (pointer: coarse)');

function pctStyle(box) {
  return `--left:${box.left}%;--top:${box.top}%;--width:${box.width}%;--height:${box.height}%;`;
}

function optimizedImageSrc(src) {
  return src.replace(/^slides\//, 'slides-webp/').replace(/\.png$/i, '.webp');
}

function optimizedVideoSrc(src) {
  const fileName = src.split('/').pop();
  const folder = MOBILE_VIDEO_QUERY.matches ? 'media-mobile' : 'media-desktop';
  return `assets/${folder}/${fileName}`;
}

function slideElement(index) {
  return stage.querySelector(`[data-slide="${index}"]`);
}

function loadSlideImage(index) {
  const slide = slideElement(index);
  if (!slide) return;
  const image = slide.querySelector('.slide-image');
  if (image && !image.src) {
    image.src = image.dataset.src;
  }
}

function loadSlideVideos(index) {
  const slide = slideElement(index);
  if (!slide) return;
  slide.querySelectorAll('video[data-src]').forEach(video => {
    const src = optimizedVideoSrc(video.dataset.src);
    if (video.dataset.loadedSrc !== src) {
      video.src = src;
      video.dataset.loadedSrc = src;
      video.load();
    }
  });
}

function preloadNearbyImages(index) {
  [index - 1, index, index + 1].forEach(loadSlideImage);
}

function makeReturnButton(label, className, targetSlide) {
  const button = document.createElement('button');
  button.className = `slide-return ${className}`;
  button.type = 'button';
  button.textContent = label;
  button.setAttribute('aria-label', label === 'Men\u00fa' ? 'Volver al men\u00fa' : 'Volver');
  button.addEventListener('click', event => {
    event.stopPropagation();
    goTo(targetSlide);
  });
  return button;
}

function goTo(index) {
  if (!slides.length) return;
  const next = Math.max(0, Math.min(slides.length - 1, index));
  const oldSlide = stage.querySelector('.slide.is-active');
  if (oldSlide) {
    oldSlide.classList.remove('is-active');
    oldSlide.querySelectorAll('video').forEach(video => video.pause());
  }
  current = next;
  loadSlideImage(current);
  loadSlideVideos(current);
  preloadNearbyImages(current);
  const active = stage.querySelector(`[data-slide="${current}"]`);
  active.classList.add('is-active');
  counter.value = `${current + 1} / ${slides.length}`;
  location.hash = `slide-${current + 1}`;
  active.querySelectorAll('video').forEach(video => {
    video.currentTime = 0;
    const play = video.play();
    if (play && typeof play.catch === 'function') play.catch(() => {});
  });
}

function makeSlide(slide) {
  const section = document.createElement('article');
  section.className = 'slide';
  section.dataset.slide = slide.index;
  section.setAttribute('aria-label', slide.title || `Diapositiva ${slide.index + 1}`);
  const hasMenuLink = slide.links.some(item => item.slide === 0);
  const isVideoSlide = slide.videos.length > 0;

  const image = document.createElement('img');
  image.className = 'slide-image';
  image.dataset.src = optimizedImageSrc(slide.image);
  image.alt = slide.title || '';
  image.decoding = 'async';
  image.draggable = false;
  section.appendChild(image);

  slide.videos.forEach(item => {
    if (!item.box) return;
    const video = document.createElement('video');
    video.className = 'video-layer';
    video.dataset.src = item.src;
    video.controls = true;
    video.playsInline = true;
    video.muted = true;
    video.preload = 'none';
    video.style.cssText = pctStyle(item.box);
    section.appendChild(video);
  });

  slide.links.forEach(item => {
    if (!item.box) return;
    const button = document.createElement('button');
    button.className = 'hotspot';
    button.type = 'button';
    button.title = item.label || 'Boton';
    button.setAttribute('aria-label', item.label || 'Boton');
    button.style.cssText = pctStyle(item.box);
    button.addEventListener('click', event => {
      event.stopPropagation();
      if (typeof item.slide === 'number') {
        goTo(item.slide);
      } else if (item.href) {
        window.open(item.href, item.external ? '_blank' : '_self');
      }
    });
    section.appendChild(button);
  });

  if (BACK_TARGETS[slide.index] !== undefined) {
    const backClass = STACKED_BACK_BUTTON_SLIDES.has(slide.index)
      ? 'back-return back-return-stacked'
      : 'back-return';
    section.appendChild(makeReturnButton('Volver', backClass, BACK_TARGETS[slide.index]));
  }

  if (slide.index !== 0 && (!hasMenuLink || isVideoSlide)) {
    section.appendChild(makeReturnButton('Men\u00fa', 'menu-return', 0));
  }

  section.addEventListener('click', event => {
    if (event.target.closest('button, video')) return;
    goTo(current + 1);
  });

  return section;
}

function init() {
  slides = PRESENTATION.slides;
  stage.replaceChildren(...slides.map(makeSlide));
  const match = location.hash.match(/slide-(\d+)/);
  goTo(match ? Number(match[1]) - 1 : 0);
}

prevButton.addEventListener('click', () => goTo(current - 1));
nextButton.addEventListener('click', () => goTo(current + 1));
fullscreenButton.addEventListener('click', () => {
  if (document.fullscreenElement) {
    document.exitFullscreen();
  } else {
    document.documentElement.requestFullscreen();
  }
});

window.addEventListener('keydown', event => {
  if (event.key === 'ArrowRight' || event.key === 'PageDown' || event.key === ' ') {
    event.preventDefault();
    goTo(current + 1);
  }
  if (event.key === 'ArrowLeft' || event.key === 'PageUp') {
    event.preventDefault();
    goTo(current - 1);
  }
  if (event.key === 'Home') goTo(0);
  if (event.key === 'End') goTo(slides.length - 1);
});

window.addEventListener('hashchange', () => {
  const match = location.hash.match(/slide-(\d+)/);
  if (match) goTo(Number(match[1]) - 1);
});

MOBILE_VIDEO_QUERY.addEventListener('change', () => {
  stage.querySelectorAll('video[data-loaded-src]').forEach(video => {
    video.pause();
    video.removeAttribute('src');
    delete video.dataset.loadedSrc;
    video.load();
  });
  loadSlideVideos(current);
});

init();
